import { findJSXAttribute, isJSXComponent } from "../../utils/jsx-utils.js";
describe('jsx-utils', () => {
    describe('findJSXAttribute', () => {
        it('should find an attribute by name', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXIdentifier', name: 'Image' },
                attributes: [
                    {
                        type: 'JSXAttribute',
                        name: { type: 'JSXIdentifier', name: 'src' },
                        value: {
                            type: 'Literal',
                            value: 'https://example.com/image.png',
                        },
                    },
                ],
                selfClosing: true,
            };
            const attribute = findJSXAttribute(node, 'src');
            expect(attribute).not.toBeNull();
            expect(attribute?.name.type).toBe('JSXIdentifier');
            expect(attribute?.name.name).toBe('src');
        });
        it('should return null when attribute is not found', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXIdentifier', name: 'Image' },
                attributes: [
                    {
                        type: 'JSXAttribute',
                        name: { type: 'JSXIdentifier', name: 'alt' },
                        value: { type: 'Literal', value: 'Alt text' },
                    },
                ],
                selfClosing: true,
            };
            expect(findJSXAttribute(node, 'src')).toBeNull();
        });
        it('should return null for elements with no attributes', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXIdentifier', name: 'Image' },
                attributes: [],
                selfClosing: true,
            };
            expect(findJSXAttribute(node, 'src')).toBeNull();
        });
        it('should find the correct attribute among multiple attributes', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXIdentifier', name: 'Image' },
                attributes: [
                    {
                        type: 'JSXAttribute',
                        name: { type: 'JSXIdentifier', name: 'alt' },
                        value: { type: 'Literal', value: 'Alt text' },
                    },
                    {
                        type: 'JSXAttribute',
                        name: { type: 'JSXIdentifier', name: 'src' },
                        value: {
                            type: 'Literal',
                            value: 'https://example.com/image.png',
                        },
                    },
                    {
                        type: 'JSXAttribute',
                        name: { type: 'JSXIdentifier', name: 'width' },
                        value: { type: 'Literal', value: '100' },
                    },
                ],
                selfClosing: true,
            };
            const attribute = findJSXAttribute(node, 'src');
            expect(attribute).not.toBeNull();
            expect(attribute?.name.name).toBe('src');
        });
    });
    describe('isJSXComponent', () => {
        it('should return true when element matches component name', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXIdentifier', name: 'Image' },
                attributes: [],
                selfClosing: true,
            };
            expect(isJSXComponent(node, 'Image')).toBe(true);
        });
        it('should return false when element does not match component name', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXIdentifier', name: 'Button' },
                attributes: [],
                selfClosing: true,
            };
            expect(isJSXComponent(node, 'Image')).toBe(false);
        });
        it('should return false for non-JSXIdentifier name types', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXMemberExpression' },
                attributes: [],
                selfClosing: true,
            };
            expect(isJSXComponent(node, 'Image')).toBe(false);
        });
        it('should be case-sensitive', () => {
            const node = {
                type: 'JSXOpeningElement',
                name: { type: 'JSXIdentifier', name: 'Image' },
                attributes: [],
                selfClosing: true,
            };
            expect(isJSXComponent(node, 'image')).toBe(false);
            expect(isJSXComponent(node, 'IMAGE')).toBe(false);
            expect(isJSXComponent(node, 'Image')).toBe(true);
        });
    });
});
